                    className={`px-2 py-0.5 text-[9px] font-bold rounded transition-all ${tempMatchMode === 'and' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    AND (且)
                  </button>
                  <button 
                    onClick={() => setTempMatchMode('or')}
                    className={`px-2 py-0.5 text-[9px] font-bold rounded transition-all ${tempMatchMode === 'or' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    OR (或)
                  </button>
               </div>
             </div>

             <div className="space-y-2 border-l-2 border-slate-700 pl-3">
               {tempFilters.map((filter, idx) => {
                  const uniqueVals = filter.operator === 'in' ? getUniqueValues(data, filter.field) : [];
                  return (
                   <div key={idx} className="bg-slate-900/50 p-2 rounded border border-slate-700 space-y-2 relative group/filter">
                     <div className="flex gap-2">
                        <select 
                          className="flex-1 text-[10px] font-medium text-slate-200 bg-slate-800 border-none rounded py-1 px-1 focus:ring-1 focus:ring-indigo-500 outline-none"
                          value={filter.field} onChange={e => updateFilter(idx, { field: e.target.value, values: [] })}
                        >
                          {fields.map(f => <option key={f} value={f}>{f}</option>)}
                        </select>
                        <button onClick={() => setTempFilters(tempFilters.filter((_, i) => i !== idx))} className="text-slate-600 hover:text-red-400 transition-colors">
                          <Trash2 className="w-3 h-3" />
                        </button>
                     </div>

                     <div className="flex gap-2">
                        <select 
                          className="flex-1 text-[10px] text-indigo-300 bg-slate-950 border border-slate-700 rounded py-1 px-1 outline-none font-bold"
                          value={filter.operator} onChange={e => updateFilter(idx, { operator: e.target.value as FilterOperator })}
                        >
                          {Operators.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                        </select>
                     </div>

                     {filter.operator === 'in' ? (
                       <div className="max-h-24 overflow-y-auto dark-scroll bg-slate-950 rounded border border-slate-800 p-1 shadow-inner">
                          {uniqueVals.length === 0 && <div className="text-[9px] text-slate-600 text-center py-2 italic">无可用数据</div>}
                          {uniqueVals.map(val => (
                            <label key={val} className="flex items-center px-1.5 py-1 hover:bg-slate-800 cursor-pointer rounded group">
                               <div className={`w-3 h-3 rounded-[2px] border border-slate-600 mr-2 flex items-center justify-center transition-colors ${filter.values.includes(val) ? 'bg-indigo-600 border-indigo-600' : 'bg-slate-900'}`}>
                                  {filter.values.includes(val) && <Check className="w-2.5 h-2.5 text-white" />}
                               </div>
                               <span className="text-[10px] text-slate-400 group-hover:text-slate-200 truncate">{val}</span>
                               <input type="checkbox" className="hidden" checked={filter.values.includes(val)} onChange={() => {
                                 const next = filter.values.includes(val) ? filter.values.filter(v => v !== val) : [...filter.values, val];
                                 updateFilter(idx, { values: next });
                               }} />
                            </label>
                          ))}
                       </div>
                     ) : (
                       <div className="flex gap-2 items-center">
                          <input 
                             type="text" placeholder="值 A"
                             className="flex-1 text-[10px] bg-slate-950 border border-slate-700 text-white rounded px-2 py-1 outline-none focus:border-indigo-500"
                             value={filter.val1 ?? ''} onChange={e => updateFilter(idx, { val1: e.target.value })}
                          />
                          {filter.operator === 'between' && (
                            <>
                              <span className="text-slate-500 text-[10px] font-bold">至</span>
                              <input 
                                 type="text" placeholder="值 B"
                                 className="flex-1 text-[10px] bg-slate-950 border border-slate-700 text-white rounded px-2 py-1 outline-none focus:border-indigo-500"
                                 value={filter.val2 ?? ''} onChange={e => updateFilter(idx, { val2: e.target.value })}
                              />
                            </>
                          )}
                       </div>
                     )}

                     {idx < tempFilters.length - 1 && (
                       <div className="absolute -bottom-3 left-4 bg-slate-800 px-2 py-0.5 rounded text-[8px] font-bold text-indigo-400 border border-slate-700 z-10">
                          {tempMatchMode.toUpperCase()}
                       </div>
                     )}
                   </div>
                  );
               })}

               <button onClick={addFilter} className="w-full mt-2 py-2 border border-dashed border-slate-700 rounded-md text-[9px] text-slate-500 hover:text-indigo-400 hover:border-indigo-500/50 hover:bg-indigo-500/5 transition-all flex items-center justify-center">
                  <Plus className="w-3 h-3 mr-1" /> 添加新条件
               </button>
             </div>
          </div>

          <button onClick={handleSave} className="w-full bg-indigo-600 hover:bg-indigo-500 text-white py-2 rounded text-[10px] font-bold uppercase tracking-wide flex items-center justify-center transition-all shadow-lg active:scale-95">
             <Save className="w-3 h-3 mr-1.5" /> 保存并应用
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-1">
      {buckets.length === 0 && <div className="text-[10px] text-slate-600 italic text-center py-2">未添加分组</div>}
      {buckets.map((bucket, index) => (
        <div key={bucket.id} className="group relative flex items-center justify-between p-2 bg-slate-800 hover:bg-slate-750 border border-transparent hover:border-slate-600 rounded text-sm transition-all text-slate-200">
          <div className="flex flex-col min-w-0 pr-2">
              <span className="font-medium text-xs truncate">{bucket.label}</span>
              {bucket.filters.length > 0 && (
                  <div className="flex items-center gap-1 mt-0.5">
                      {bucket.matchMode === 'or' ? <ShieldAlert className="w-2.5 h-2.5 text-amber-500" /> : <ShieldCheck className="w-2.5 h-2.5 text-emerald-500" />}
                      <span className="text-[9px] text-slate-500 truncate max-w-[120px]">
                          {bucket.filters.length}个条件 ({bucket.matchMode === 'or' ? '满足其一' : '全部满足'})
                      </span>
                  </div>
              )}
          </div>
          <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity absolute right-1 bg-slate-800 rounded border border-slate-700 shadow-md">
             <button onClick={() => handleMove(index, -1)} disabled={index === 0} className="p-1 text-slate-400 hover:text-white disabled:opacity-20"><ArrowUp className="w-3 h-3" /></button>
             <button onClick={() => handleMove(index, 1)} disabled={index === buckets.length - 1} className="p-1 text-slate-400 hover:text-white disabled:opacity-20"><ArrowDown className="w-3 h-3" /></button>
             <button onClick={() => handleDuplicate(bucket, index)} title="复制" className="p-1 text-slate-400 hover:text-indigo-400"><Copy className="w-3 h-3" /></button>
             <button onClick={() => handleEdit(bucket)} title="编辑" className="p-1 text-slate-400 hover:text-white"><Edit2 className="w-3 h-3" /></button>
             <button onClick={() => onChange(buckets.filter(b => b.id !== bucket.id))} title="删除" className="p-1 text-slate-400 hover:text-red-400"><Trash2 className="w-3 h-3" /></button>
          </div>
        </div>
      ))}
    </div>
  );
};

