import React, { useState, useMemo } from 'react';
import { DataRecord, PivotConfig, PivotResult } from './types';
import FileUpload from './components/FileUpload';
import ConfigPanel from './components/ConfigPanel';
import PivotTableRender from './components/PivotTableRender';
import { performPivot, generateExportData } from './utils/pivotEngine';
import { Download, Table as TableIcon, Activity, Database, X, LayoutTemplate, Box } from 'lucide-react';
import { utils, writeFile } from 'xlsx';

const App: React.FC = () => {
  // --- State ---
  const [rawData, setRawData] = useState<DataRecord[]>([]);
  const [fileName, setFileName] = useState<string>('');
  const [fields, setFields] = useState<string[]>([]);

  // View State
  const [viewMode, setViewMode] = useState<'table' | 'heatmap'>('table');
  const [density, setDensity] = useState<'compact' | 'normal'>('normal');

  // Initial Config
  const [config, setConfig] = useState<PivotConfig>({
    customRows: [],
    customCols: [],
    values: [],
    filters: {}
  });

  // --- Handlers ---
  const handleDataLoaded = (data: DataRecord[], name: string) => {
    setRawData(data);
    setFileName(name);
    if (data.length > 0) {
      const keys = Object.keys(data[0]);
      setFields(keys);
      // Smart default: guess first text field as row, first number as value
      const likelyRow = keys.find(k => typeof data[0][k] === 'string') || keys[0];
      const likelyVal = keys.find(k => typeof data[0][k] === 'number');

      setConfig({
        customRows: [{ id: 'default_row', label: likelyRow, filters: [] }], 
        customCols: [],
        values: likelyVal ? [{ id: 'val_1', field: likelyVal, aggregator: 'sum' }] : [],
        filters: {}
      });
    }
  };

  const handleExport = () => {
    if (!pivotResult || rawData.length === 0) return;
    try {
      const exportData = generateExportData(pivotResult);
      const ws = utils.aoa_to_sheet(exportData);
      const wb = utils.book_new();
      utils.book_append_sheet(wb, ws, "Pivot Data");
      const exportName = fileName ? fileName.replace(/\.[^/.]+$/, "") + "_pivot.xlsx" : "pivot_export.xlsx";
      writeFile(wb, exportName);
    } catch (error) {
      console.error("Export failed:", error);
      alert("Failed to export data.");
    }
  };

  const handleCloseFile = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("确定要关闭当前文件吗？未保存的配置将会丢失。")) {
      setRawData([]);
      setFileName('');
      setFields([]);
      setConfig({ customRows: [], customCols: [], values: [], filters: {} });
    }
  };

  // --- Computation ---
  const pivotResult: PivotResult = useMemo(() => {
    if (rawData.length === 0) return { rowNodes: [], colNodes: [], flatColHeaders: [] };
    return performPivot(rawData, config);
  }, [rawData, config]);

  // --- Empty State (Upload) ---
  if (rawData.length === 0) {
    return (
      <div className="h-full w-full bg-slate-50 flex flex-col items-center justify-center p-8 text-slate-800">
        <div className="max-w-md w-full flex flex-col items-center gap-6">
           <div className="w-16 h-16 bg-white rounded-2xl shadow-lg flex items-center justify-center mb-4 ring-1 ring-slate-100">
              <Box className="w-8 h-8 text-indigo-600" />
           </div>

           <div className="text-center space-y-2">
             <h1 className="text-2xl font-bold tracking-tight text-slate-900">
               PivotMaster
             </h1>
             <p className="text-slate-500">
               上传文件开始数据分析
             </p>
           </div>

           <div className="w-full">
              <FileUpload onDataLoaded={handleDataLoaded} />
           </div>

           <div className="flex gap-4 text-xs font-mono text-slate-400 uppercase tracking-widest">
              <span>.CSV</span>
              <span className="text-slate-300">•</span>
              <span>.JSON</span>
              <span className="text-slate-300">•</span>
              <span>.XLSX</span>
           </div>
        </div>
      </div>
    );
  }

  // --- Main Application Layout ---
  return (
    <div className="h-full w-full flex flex-row overflow-hidden bg-slate-900 text-sm">

      {/* Sidebar: Config Panel */}
      <ConfigPanel 
        fields={fields} 
        config={config} 
        onConfigChange={setConfig} 
        data={rawData}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 bg-slate-50 h-full relative">

        {/* Title Bar / Toolbar */}
        <header className="h-12 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0 shadow-sm z-30 app-drag">

           {/* Left: File Context */}
           <div className="flex items-center gap-3 min-w-0 no-drag">
              <div className="flex items-center gap-2 text-slate-700">
                 <LayoutTemplate className="w-4 h-4 text-slate-400" />
                 <span className="font-semibold truncate max-w-[200px]" title={fileName}>{fileName}</span>
                 <span className="text-[10px] text-slate-400 bg-slate-100 px-2 py-0.5 rounded border border-slate-200 font-bold">
                    {rawData.length.toLocaleString()} ROWS
                 </span>
              </div>
           </div>

           {/* Right: Actions */}
           <div className="flex items-center gap-2 no-drag" style={{ WebkitAppRegion: 'no-drag' } as any}>

              {/* View Toggle */}
              <div className="flex bg-slate-100 p-0.5 rounded-lg border border-slate-200">
                  <button 
                    onClick={() => setViewMode('table')}
                    className={`flex items-center justify-center w-9 h-7 rounded-md text-xs font-medium transition-all ${
                      viewMode === 'table' 
                        ? 'bg-white text-indigo-600 shadow-sm' 
                        : 'text-slate-400 hover:text-slate-600'
                    }`}
                    title="Grid View"
                  >
                    <TableIcon className="w-4 h-4" />
                  </button>
                  <button 
                    onClick={() => setViewMode('heatmap')}
                    className={`flex items-center justify-center w-9 h-7 rounded-md text-xs font-medium transition-all ${
                      viewMode === 'heatmap' 
                        ? 'bg-white text-indigo-600 shadow-sm' 
                        : 'text-slate-400 hover:text-slate-600'
                    }`}
                    title="Heatmap View"
                  >
                    <Activity className="w-4 h-4" />
                  </button>
              </div>

              <div className="w-px h-4 bg-slate-200 mx-1" />

              <button 
                onClick={handleExport}
                className="flex items-center gap-2 px-4 py-1.5 bg-slate-900 hover:bg-slate-800 text-white rounded-md shadow-sm transition-all text-xs font-bold active:scale-95"
              >
                <Download className="w-3.5 h-3.5" />
                Export
              </button>

              <button 
                onClick={handleCloseFile}
                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-md transition-all cursor-pointer relative z-50 ml-1"
                title="Close File"
              >
                 <X className="w-5 h-5" />
              </button>
           </div>
        </header>

        {/* Pivot Table Container - Full Screen Edge to Edge */}
        <main className="flex-1 overflow-hidden relative w-full h-full bg-slate-100">
           <div className="absolute inset-0 bg-white overflow-hidden flex flex-col">
             <div className="flex-1 relative overflow-hidden">
               <PivotTableRender 
                  result={pivotResult} 
                  config={config} 
                  viewMode={viewMode}
                  density={density}
               />
             </div>
           </div>
        </main>

        {/* Status Bar */}
        <div className="h-7 bg-white border-t border-slate-200 shrink-0 flex items-center justify-between px-4 text-[10px] text-slate-400 uppercase tracking-widest font-medium">
           <div className="flex gap-4">
              <span className="flex items-center gap-1.5">
                 <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shadow-[0_0_4px_#10b981]"></div>
                 Ready
              </span>
           </div>
           <div className="flex gap-3 items-center no-drag">
              <button onClick={() => setDensity(d => d === 'normal' ? 'compact' : 'normal')} className="hover:text-indigo-600 transition-colors">
                 {density} Density
              </button>
           </div>
        </div>

      </div>
    </div>
  );
};

export default App;

